import{_ as a,o as t,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Enable Google Marketing Platform","description":"","frontmatter":{"title":"Enable Google Marketing Platform","slug":"enable-google-marketing-platform"},"headers":[],"relativePath":"marketer-hub/enable-google-marketing-platform.md","filePath":"marketer-hub/enable-google-marketing-platform.md"}'),o={name:"marketer-hub/enable-google-marketing-platform.md"};function i(l,e,s,g,h,c){return t(),r("div",null,[...e[0]||(e[0]=[n('<h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Google Marketing Platform, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Set your <a href="./advanced-settings-configuration.html#local-currency">local currency</a>.</p></li><li><p>Enabled Ads for your Branch account.</p><ul><li>Contact your Branch account manager or visit <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">https://branch.io/pricing</a></li></ul></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Admin access to your Google Marketing Platform (DV360 and/or CM360) account.</p></li></ol><h2 id="enable-google-marketing-platform" tabindex="-1">Enable Google Marketing Platform <a class="header-anchor" href="#enable-google-marketing-platform" aria-label="Permalink to &quot;Enable Google Marketing Platform&quot;">​</a></h2><h3 id="_1-generate-link-ids" tabindex="-1">1. Generate Link IDs <a class="header-anchor" href="#_1-generate-link-ids" aria-label="Permalink to &quot;1. Generate Link IDs&quot;">​</a></h3><p>Link IDs are needed for Branch to connect to GMP.</p><div class="info custom-block"><p class="custom-block-title">Link ID Creation</p><p>You only need one Link ID per app:</p><ul><li>If you are using <strong>both</strong> Campaign Manager and Display &amp; Video 360, generate the Link ID in Campaign Manager.</li><li>If you&#39;re <strong>only</strong> using Display &amp; Video 360, generate your Link ID in Display &amp; Video 360.</li></ul></div><h4 id="generate-link-id-in-cm360" tabindex="-1">Generate Link ID in CM360 <a class="header-anchor" href="#generate-link-id-in-cm360" aria-label="Permalink to &quot;Generate Link ID in CM360&quot;">​</a></h4><p>In CM360, go to <strong>Advertiser &gt; Floodlight &gt; Floodlight Configuration</strong>, and select the app you are configuring. Select Branch as your partner, and save the generated Link ID for the next step.</p><h4 id="generate-link-id-in-dv360" tabindex="-1">Generate Link ID in DV360 <a class="header-anchor" href="#generate-link-id-in-dv360" aria-label="Permalink to &quot;Generate Link ID in DV360&quot;">​</a></h4><p>In DV360, go to <strong>Advertiser &gt; Resources &gt; Floodlight &gt; Basic Details &gt; Third-Party App Analytics &gt; Edit</strong>. Select <strong>Create New Link</strong>, and choose your platform. Save the generated Link ID for the next step.</p><h3 id="_2-connect-gmp-in-branch" tabindex="-1">2. Connect GMP in Branch <a class="header-anchor" href="#_2-connect-gmp-in-branch" aria-label="Permalink to &quot;2. Connect GMP in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads &gt;</strong> <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a>, find/search for Google Marketing Platform. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/ads/partner-management/a_google_marketing_platform?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p>Enter the Link IDs from <a href="./enable-google-marketing-platform.html#1-generate-link-ids">Step 1</a> in the <a href="https://dashboard.branch.io/ads/partner-management/a_google_marketing_platform?tab=settings" target="_blank" rel="noreferrer">Account Settings tab</a> and click <strong>Save &amp; Enable</strong>.</p><h3 id="_3-configure-events" tabindex="-1">3. Configure Events <a class="header-anchor" href="#_3-configure-events" aria-label="Permalink to &quot;3. Configure Events&quot;">​</a></h3><p>After inputting your GMP Link IDs into Branch, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_google_marketing_platform?tab=events" target="_blank" rel="noreferrer">Events Config tab</a> to configure your events.</p><div class="info custom-block"><p class="custom-block-title">Limited Custom Events</p><p>Google Marketing Platform only supports 10 custom events, so we recommend choosing which events are most valuable.</p></div><p>You should see the events you are tracking with the Branch SDK here when you Add Event Mappings. For more details on Google Ads and Branch event &amp; metadata mapping, see the specifications here.</p><h3 id="_4-configure-attribution-windows" tabindex="-1">4. Configure Attribution Windows <a class="header-anchor" href="#_4-configure-attribution-windows" aria-label="Permalink to &quot;4. Configure Attribution Windows&quot;">​</a></h3><p>After configuring your events, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_google_marketing_platform?tab=attribution_windows" target="_blank" rel="noreferrer">Attribution Windows tab</a> to set windows by attribution type.</p><p>You have full freedom to choose your attribution windows; however, it may cause discrepancies between the Branch and GMP Dashboards when comparing. It is recommended that attribution windows are set to be the same to reduce discrepancies.</p>',21)])])}const m=a(o,[["render",i]]);export{p as __pageData,m as default};
